/* ------------------------------------------------------------------ */
/* Combinator: niches x styles = 2001 templates                       */
/* ------------------------------------------------------------------ */

function buildCatalog(): CatalogEntry[] {
  const entries: CatalogEntry[] = [];
  const numStyles = STYLE_PRESETS.length;

  // E-commerce: 91 niches × 9 styles each, cap at 801
  for (let i = 0; i < EN.length && entries.length < 801; i++) {
    const n = EN[i];
    const defaultFeats = n.feats.length ? n.feats : [{icon:"zap",title:"Fast",description:"Lightning fast"},{icon:"shield-check",title:"Secure",description:"Enterprise security"},{icon:"sparkles",title:"Beautiful",description:"Stunning design"}];
    for (let s = 0; s < 9 && entries.length < 801; s++) {
      const si = s % numStyles;
      const style = STYLE_PRESETS[si];
      const layout = ECOM_LAYOUTS[(i + s) % ECOM_LAYOUTS.length];
      const sections = layout(n.hl, n.sub, n.kw, defaultFeats, true);
      entries.push({
        id: `${n.id}-${style.id}`,
        name: `${n.name} - ${style.name}`,
        description: n.desc,
        category: n.cat,
        tags: [...n.tags, style.id.split("-")[0]],
        ecommerce: true,
        styleIndex: si,
        config: {
          siteName: n.name,
          tagline: n.sub,
          sections,
          products: n.products,
        },
      });
    }
  }

  // Websites: 173 niches × 7-8 styles each, cap at 1200
  for (let i = 0; i < WN.length && entries.length < 2001; i++) {
    const n = WN[i];
    const numPerNiche = i < 3 ? 8 : 7;
    const defaultFeats = [{icon:"zap",title:"Lightning Fast",description:"Built for speed"},{icon:"shield-check",title:"Secure",description:"Enterprise security"},{icon:"sparkles",title:"Beautiful",description:"Stunning design"}];
    for (let s = 0; s < numPerNiche && entries.length < 2001; s++) {
      const si = s % numStyles;
      const style = STYLE_PRESETS[si];
      const layout = WEB_LAYOUTS[(i + s) % WEB_LAYOUTS.length];
      const sections = layout(n.hl, n.sub, n.id.replace(/-/g, " "), defaultFeats, false);
      entries.push({
        id: `${n.id}-${style.id}`,
        name: `${n.name} - ${style.name}`,
        description: n.desc,
        category: n.cat,
        tags: [...n.tags, style.id.split("-")[0]],
        ecommerce: false,
        styleIndex: si,
        config: {
          siteName: n.name,
          tagline: n.sub,
          sections,
        },
      });
    }
  }

  /* ---------------------------------------------------------------- */
  /* Expansion packs: +2000 e-commerce, +3000 website = 7001 total.    */
  /* New IDs are 3-segment (niche-style-collection) so they can never  */
  /* collide with the 2-segment base IDs above. A `seen` set is an     */
  /* explicit dedupe guard — nothing is added twice.                   */
  /* ---------------------------------------------------------------- */
  const seen = new Set(entries.map((e) => e.id));

  // Each collection re-mixes an existing niche+style with a different
  // layout arrangement, producing a genuinely distinct template.
  const COLLECTIONS = [
    { id: "signature", name: "Signature", shift: 1 },
    { id: "studio", name: "Studio", shift: 4 },
    { id: "atelier", name: "Atelier", shift: 7 },
  ];

  const ECOM_EXTRA = 2000;
  const WEB_EXTRA = 3000;

  // --- E-commerce expansion ---
  let ecomAdded = 0;
  for (const col of COLLECTIONS) {
    for (let i = 0; i < EN.length && ecomAdded < ECOM_EXTRA; i++) {
      const n = EN[i];
      const feats = n.feats.length
        ? n.feats
        : [{icon:"zap",title:"Fast",description:"Lightning fast"},{icon:"shield-check",title:"Secure",description:"Enterprise security"},{icon:"sparkles",title:"Beautiful",description:"Stunning design"}];
      for (let s = 0; s < numStyles && ecomAdded < ECOM_EXTRA; s++) {
        const style = STYLE_PRESETS[s];
        const id = `${n.id}-${style.id}-${col.id}`;
        if (seen.has(id)) continue;
        const layout = ECOM_LAYOUTS[(i + s + col.shift) % ECOM_LAYOUTS.length];
        const sections = layout(n.hl, n.sub, n.kw, feats, true);
        entries.push({
          id,
          name: `${n.name} - ${style.name} ${col.name}`,
          description: n.desc,
          category: n.cat,
          tags: [...n.tags, style.id.split("-")[0], col.id],
          ecommerce: true,
          styleIndex: s,
          config: { siteName: n.name, tagline: n.sub, sections, products: n.products },
        });
        seen.add(id);
        ecomAdded++;
      }
    }
  }

  // --- Website expansion ---
  let webAdded = 0;
  const webFeats = [{icon:"zap",title:"Lightning Fast",description:"Built for speed"},{icon:"shield-check",title:"Secure",description:"Enterprise security"},{icon:"sparkles",title:"Beautiful",description:"Stunning design"}];
  for (const col of COLLECTIONS) {
    for (let i = 0; i < WN.length && webAdded < WEB_EXTRA; i++) {
      const n = WN[i];
      for (let s = 0; s < numStyles && webAdded < WEB_EXTRA; s++) {
        const style = STYLE_PRESETS[s];
        const id = `${n.id}-${style.id}-${col.id}`;
        if (seen.has(id)) continue;
        const layout = WEB_LAYOUTS[(i + s + col.shift) % WEB_LAYOUTS.length];
        const sections = layout(n.hl, n.sub, n.id.replace(/-/g, " "), webFeats, false);
        entries.push({
          id,
          name: `${n.name} - ${style.name} ${col.name}`,
          description: n.desc,
          category: n.cat,
          tags: [...n.tags, style.id.split("-")[0], col.id],
          ecommerce: false,
          styleIndex: s,
          config: { siteName: n.name, tagline: n.sub, sections },
        });
        seen.add(id);
        webAdded++;
      }
    }
  }

  /* ---------------------------------------------------------------- */
  /* Real-niche variety pack: +1500 e-commerce, +1500 website from the */
  /* fresh EN2 / WN2 niches. Same 3-segment ID scheme + Set guard.     */
  /* ---------------------------------------------------------------- */
  const NICHE_ECOM_EXTRA = 1500;
  const NICHE_WEB_EXTRA = 1500;

  // --- New e-commerce niches ---
  let ecom2Added = 0;
  for (const col of COLLECTIONS) {
    for (let i = 0; i < EN2.length && ecom2Added < NICHE_ECOM_EXTRA; i++) {
      const n = EN2[i];
      const feats = n.feats.length
        ? n.feats
        : [{icon:"zap",title:"Fast",description:"Lightning fast"},{icon:"shield-check",title:"Secure",description:"Enterprise security"},{icon:"sparkles",title:"Beautiful",description:"Stunning design"}];
      for (let s = 0; s < numStyles && ecom2Added < NICHE_ECOM_EXTRA; s++) {
        const style = STYLE_PRESETS[s];
        const id = `${n.id}-${style.id}-${col.id}`;
        if (seen.has(id)) continue;
        const layout = ECOM_LAYOUTS[(i + s + col.shift) % ECOM_LAYOUTS.length];
        const sections = layout(n.hl, n.sub, n.kw, feats, true);
        entries.push({
          id,
          name: `${n.name} - ${style.name} ${col.name}`,
          description: n.desc,
          category: n.cat,
          tags: [...n.tags, style.id.split("-")[0], col.id],
          ecommerce: true,
          styleIndex: s,
          config: { siteName: n.name, tagline: n.sub, sections, products: n.products },
        });
        seen.add(id);
        ecom2Added++;
      }
    }
  }

  // --- New website niches ---
  let web2Added = 0;
  for (const col of COLLECTIONS) {
    for (let i = 0; i < WN2.length && web2Added < NICHE_WEB_EXTRA; i++) {
      const n = WN2[i];
      for (let s = 0; s < numStyles && web2Added < NICHE_WEB_EXTRA; s++) {
        const style = STYLE_PRESETS[s];
        const id = `${n.id}-${style.id}-${col.id}`;
        if (seen.has(id)) continue;
        const layout = WEB_LAYOUTS[(i + s + col.shift) % WEB_LAYOUTS.length];
        const sections = layout(n.hl, n.sub, n.id.replace(/-/g, " "), webFeats, false);
        entries.push({
          id,
          name: `${n.name} - ${style.name} ${col.name}`,
          description: n.desc,
          category: n.cat,
          tags: [...n.tags, style.id.split("-")[0], col.id],
          ecommerce: false,
          styleIndex: s,
          config: { siteName: n.name, tagline: n.sub, sections },
        });
        seen.add(id);
        web2Added++;
      }
    }
  }

  return entries;
}

/** All 10001 catalog entries (4301 e-commerce + 5700 website). Built once on import. */
export const CATALOG: CatalogEntry[] = buildCatalog();